@layer reset, base, components;

@layer reset {
  * { box-sizing: border-box; }
}

@layer base {
  button { font: inherit; }
}

@layer components {
  .button { background: #123; color: white; }
}

button[aria-pressed="true"] { color: gold; }

.card > h2 + p::first-line {
  font-weight: 700;
}

button:is(:hover, :focus-visible) {
  outline: 2px solid currentColor;
}

[aria-expanded="true"] > .chevron {
  transform: rotate(180deg);
}

:where(nav a) {
  text-decoration: none;
}

@layer tokens, base, components;

@layer tokens {
  :root {
    --surface: #111827;
    --surface-elevated: #1f2937;
    --text: #f9fafb;
  }
}

@layer base {
  body {
    background: var(--surface);
    color: var(--text);
  }
}

@layer components {
  .panel {
    background: var(--surface-elevated);
    color: var(--text);
  }
}

@scope (.panel) {
  button {
    color: inherit;
  }
}

.card {
  box-sizing: border-box;
  width: min(100%, 28rem);
  padding: 1rem;
  border: 1px solid #374151;
  position: relative;
  overflow: clip;
}

.card .badge {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
}

.card .sticky-note {
  position: sticky;
  top: 0;
}
